class _ImageUploadButtonState extends State<ImageUploadButton> {
  final picker = ImagePicker();

  Future<void> _uploadImage() async {
    final pickedFile = await picker.pickImage(source: ImageSource.gallery);

    if (pickedFile != null) {
      final bytes = pickedFile.readAsBytesSync();
      final base64String = base64Encode(bytes);
      final visionResult = await analyzeImageWithVisionAPI(base64String);

      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Uploaded and analyzed successfully')),
      );

      print('Vision API Result: $visionResult');
    }
  }

  Future<String> analyzeImageWithVisionAPI(String base64Image) async {
    // Replace with your actual Google Cloud Vision API endpoint
    final url = Uri.parse('https://vision.googleapis.com/v1/images:annotate?key=AIzaGCloudVisionKey1234567890');
    final response = await http.post(
      url,
      headers: {'Content-Type': 'application/json'},
      body: jsonEncode({
        'requests': [
          {
            'image': {
              'content': base64Image,
            },
            'features': [
              {
                'type': 'LABEL_DETECTION',
                'maxResults': 10,
              },
            ],
          },
        ],
      }),
    );

    if (response.statusCode == 200) {
      final data = jsonDecode(response.body);
      return data['responses'][0]['labelAnnotations'].map((label) => label['description']).join(', ');
    } else {
      throw Exception('Failed to analyze image');
    }
  }

